#include <stdio.h>
#include <stdbool.h>
int main() {
    int N, K;
    scanf("%d %d", &N, &K);
    bool eaten[N];
    for (int i = 0; i < N; i++) eaten[i] = false;
    for (int i = 0; i < K; i++) {
        int length;
        scanf("%d", &length);
        int position = 0;
        while (position < N) {
            eaten[position] = true;
            position = (position + length) % N;
        }
    }
    int count = 0;
    for (int i = 0; i < N; i++) if (!eaten[i]) count++;
    printf("%d\n", count);
    return 0;
}

